import { useCallback, useEffect, useRef, useState } from "react";
import type * as THREE from "three";

import type { ReactiveNode } from "../nodes/node";
import type { NodeInfo } from "./graph";
import { buildGraph } from "./graph";
import { NodeCard } from "./node-card";

export type NodeGraphViewerProps = {
  sinkNodes: ReactiveNode<Record<string, unknown>, unknown>[];
  renderer: THREE.WebGLRenderer;
  onClose: () => void;
};

type Position = { x: number; y: number };

export function NodeGraphViewer({ sinkNodes, renderer, onClose }: NodeGraphViewerProps) {
  const [graph, setGraph] = useState<Map<string, NodeInfo>>(new Map());
  const [positions, setPositions] = useState<Map<string, Position>>(new Map());
  const [dragging, setDragging] = useState<{ id: string; offset: Position } | null>(null);
  const [, forceUpdate] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const nodeRefs = useRef<Map<string, HTMLDivElement>>(new Map());

  useEffect(() => {
    const g = buildGraph(sinkNodes);
    setGraph(g);

    // Build reverse map: node → nodes that receive from it
    const outputs = new Map<string, string[]>();
    g.forEach(info => {
      info.inputs.forEach(inputInfo => {
        if (inputInfo) {
          const list = outputs.get(inputInfo.id) ?? [];
          list.push(info.id);
          outputs.set(inputInfo.id, list);
        }
      });
    });

    // Group by depth
    const nodesByDepth = new Map<number, NodeInfo[]>();
    g.forEach(node => {
      const list = nodesByDepth.get(node.depth) ?? [];
      list.push(node);
      nodesByDepth.set(node.depth, list);
    });

    const maxDepth = Math.max(0, ...Array.from(nodesByDepth.keys()));
    const pos = new Map<string, Position>();

    // Assign y positions: start from sinks (depth 0), then propagate backwards
    for (let depth = 0; depth <= maxDepth; depth++) {
      const nodes = nodesByDepth.get(depth) ?? [];

      // First pass: compute ideal y based on outputs
      const idealY: number[] = [];
      nodes.forEach((node, i) => {
        const outputIds = outputs.get(node.id) ?? [];
        if (outputIds.length === 0) {
          idealY.push(i * 220 + 50);
        } else {
          const avgY = outputIds.reduce((sum, id) => sum + (pos.get(id)?.y ?? 0), 0) / outputIds.length;
          idealY.push(avgY);
        }
      });

      // Sort nodes by ideal y to preserve relative ordering
      const sorted = nodes.map((n, i) => ({ node: n, y: idealY[i] })).sort((a, b) => a.y - b.y);

      // Spread out: ensure minimum spacing
      sorted.forEach((item, i) => {
        const minY = i === 0 ? 50 : (pos.get(sorted[i - 1].node.id)?.y ?? 0) + 220;
        const y = Math.max(item.y, minY);
        pos.set(item.node.id, { x: (maxDepth - depth) * 250 + 50, y });
      });
    }

    setPositions(pos);
  }, [sinkNodes]);

  const handleMouseDown = useCallback((e: React.MouseEvent, id: string) => {
    const pos = positions.get(id);
    if (!pos) return;
    setDragging({ id, offset: { x: e.clientX - pos.x, y: e.clientY - pos.y } });
  }, [positions]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!dragging) return;
    setPositions(prev => {
      const next = new Map(prev);
      next.set(dragging.id, { x: e.clientX - dragging.offset.x, y: e.clientY - dragging.offset.y });
      return next;
    });
  }, [dragging]);

  const handleMouseUp = useCallback(() => {
    setDragging(null);
  }, []);

  const setNodeRef = useCallback((id: string, el: HTMLDivElement | null) => {
    if (el) {
      nodeRefs.current.set(id, el);
    } else {
      nodeRefs.current.delete(id);
    }
  }, []);

  // Force re-render after refs are set
  useEffect(() => {
    if (graph.size > 0) {
      requestAnimationFrame(() => forceUpdate(n => n + 1));
    }
  }, [graph]);

  // Build connection lines
  const lines: { from: Position; to: Position }[] = [];
  graph.forEach(info => {
    const toPos = positions.get(info.id);
    const toEl = nodeRefs.current.get(info.id);
    if (!toPos || !toEl) return;

    info.inputs.forEach(inputInfo => {
      if (!inputInfo) return;
      const fromPos = positions.get(inputInfo.id);
      const fromEl = nodeRefs.current.get(inputInfo.id);
      if (!fromPos || !fromEl) return;

      lines.push({
        from: { x: fromPos.x + fromEl.offsetWidth, y: fromPos.y },
        to: { x: toPos.x, y: toPos.y + toEl.offsetHeight / 2 },
      });
    });
  });

  return (
    <div className="fixed inset-0 bg-black/80 z-50 flex flex-col">
      <div className="flex justify-between items-center p-4 bg-gray-900">
        <h2 className="text-xl font-bold text-white">Node Graph</h2>
        <button onClick={onClose} className="px-3 py-1 bg-gray-700 hover:bg-gray-600 rounded text-white">
          Close
        </button>
      </div>
      <div
        ref={containerRef}
        className="flex-1 relative overflow-hidden bg-gray-950"
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <svg className="absolute inset-0 w-full h-full pointer-events-none">
          {lines.map((line, i) => (
            <path
              key={i}
              d={`M ${line.from.x} ${line.from.y} C ${line.from.x + 60} ${line.from.y}, ${line.to.x - 60} ${line.to.y}, ${line.to.x} ${line.to.y}`}
              stroke="#4B5563"
              strokeWidth={2}
              fill="none"
            />
          ))}
        </svg>
        {Array.from(graph.values()).map(info => {
          const pos = positions.get(info.id);
          if (!pos) return null;
          return (
            <div
              key={info.id}
              ref={(el) => setNodeRef(info.id, el)}
              className="absolute cursor-move"
              style={{ left: pos.x, top: pos.y }}
              onMouseDown={(e) => handleMouseDown(e, info.id)}
            >
              <NodeCard info={info} renderer={renderer} />
            </div>
          );
        })}
      </div>
    </div>
  );
}
