import { useEffect, useMemo, useState } from "react";
import type * as THREE from "three";

type Props = {
  value: THREE.Texture;
  renderer: THREE.WebGLRenderer;
};

export function TexturePreview({ value, renderer }: Props) {
  const [div, setDiv] = useState<HTMLDivElement | null>(null);

  const image = useMemo(() => {
    const img = value.image;

    // Drawable image - use directly
    if (img instanceof HTMLImageElement) {
      return img.cloneNode() as HTMLImageElement;
    }
    if (img instanceof HTMLCanvasElement || img instanceof ImageBitmap) {
      const el = document.createElement("img");
      const canvas = document.createElement("canvas");
      canvas.width = img.width;
      canvas.height = img.height;
      canvas.getContext("2d")!.drawImage(img, 0, 0);
      el.src = canvas.toDataURL();
      return el;
    }

    // Render target - read pixels
    const rt = value.renderTarget;
    if (rt) {
      const width = rt.width;
      const height = rt.height;
      const pixels = new Uint8Array(width * height * 4);
      renderer.readRenderTargetPixels(rt as THREE.WebGLRenderTarget, 0, 0, width, height, pixels);

      const canvas = document.createElement("canvas");
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d")!;
      const imageData = new ImageData(new Uint8ClampedArray(pixels), width, height);
      ctx.putImageData(imageData, 0, 0);

      // Flip Y
      const flipped = document.createElement("canvas");
      flipped.width = width;
      flipped.height = height;
      const fctx = flipped.getContext("2d")!;
      fctx.translate(0, height);
      fctx.scale(1, -1);
      fctx.drawImage(canvas, 0, 0);

      const el = document.createElement("img");
      el.src = flipped.toDataURL();
      return el;
    }

    return null;
  }, [value, renderer]);

  useEffect(() => {
    if (!div || !image) return;
    div.innerHTML = "";
    image.style.width = "150px";
    image.style.height = "150px";
    image.style.objectFit = "contain";
    div.appendChild(image);
  }, [div, image]);

  return <div ref={setDiv} className="w-[150px] h-[150px] border border-gray-600 bg-gray-800" />;
}
